const { capitalize, camelCase, truncate } = require('../src/index');

describe('capitalize', () => {
  test('capitalizes the first character', () => {
    expect(capitalize('hello')).toBe('Hello');
  });

  test('returns empty string for empty input', () => {
    expect(capitalize('')).toBe('');
  });

  test('throws TypeError for non-string input', () => {
    expect(() => capitalize(42)).toThrow(TypeError);
    expect(() => capitalize(null)).toThrow(TypeError);
    expect(() => capitalize(undefined)).toThrow(TypeError);
  });

  test('only affects the first character', () => {
    expect(capitalize('hELLO')).toBe('HELLO');
  });
});

describe('camelCase', () => {
  test('converts kebab-case to camelCase', () => {
    expect(camelCase('foo-bar')).toBe('fooBar');
  });

  test('converts space-separated to camelCase', () => {
    expect(camelCase('hello world')).toBe('helloWorld');
  });

  test('handles mixed separators', () => {
    expect(camelCase('foo-bar baz')).toBe('fooBarBaz');
  });

  test('returns empty string for empty input', () => {
    expect(camelCase('')).toBe('');
  });

  test('throws TypeError for non-string input', () => {
    expect(() => camelCase(42)).toThrow(TypeError);
    expect(() => camelCase(null)).toThrow(TypeError);
  });
});

describe('truncate', () => {
  test('truncates long strings and appends ...', () => {
    expect(truncate('Hello, world!', 5)).toBe('He...');
  });

  test('returns string unchanged if within limit', () => {
    expect(truncate('Hi', 5)).toBe('Hi');
  });

  test('handles exact length match', () => {
    expect(truncate('Hello', 5)).toBe('Hello');
  });

  test('throws TypeError for non-string first argument', () => {
    expect(() => truncate(42, 5)).toThrow(TypeError);
  });

  test('throws TypeError for non-number second argument', () => {
    expect(() => truncate('hello', '5')).toThrow(TypeError);
  });

  test('throws RangeError for negative maxLength', () => {
    expect(() => truncate('hello', -1)).toThrow(RangeError);
  });
});
